void solve(int CASE)
{
	ll n, m, k; cin >> n >> m >> k;
	var p = vector<pll>(k + 1);
	var mpx = map<ll, ll>();
	var mpy = map<ll, ll>();
	fa(i, 1, k) {
		cin >> p[i].px >> p[i].py;
		mpx[p[i].px]++;
		mpy[p[i].py]++;
	}

	// (i, j) 非预设格子的贡献
	ll free = (n - mpx.size()) * (m - mpy.size()) % mod;
	ll ans = 0;
	if (free)ans = free * Math::fastPow(2, ((n - 1) * (m - 1) - k) % (mod - 1), mod) % mod;

	// (i, j) 为预设格子的贡献
	ll cnt = 0;
	fa(i, 1, k) {
		const var& [x, y] = p[i];
		if (mpx[x] == 1 and mpy[y] == 1)cnt++;
	}
	if (cnt) {
		ans += cnt * Math::fastPow(2, ((n - 1) * (m - 1) - k + 1) % (mod - 1), mod) % mod;
		ans %= mod;
	}

	cout << ans << endl;
	return;
}
